-- ============================================================
-- Step 3: areas.salon_count を実際の salon_areas 件数に更新
-- ============================================================

UPDATE areas a SET salon_count = sub.actual_count
FROM (
    SELECT sa.area_id, count(*) as actual_count
    FROM salon_areas sa
    GROUP BY sa.area_id
) sub
WHERE sub.area_id = a.id AND a.salon_count != sub.actual_count;
